import{_ as i,o as e,c as a,a0 as n}from"./chunks/framework.Dx25mwie.js";const c=JSON.parse('{"title":"Go-Spring 实战第 24 课 —— 日志配置：组织日志链路","description":"","frontmatter":{},"headers":[],"relativePath":"docs/8.wechat-series/24-logging-config-governance.md","filePath":"docs/8.wechat-series/24-logging-config-governance.md"}'),p={name:"docs/8.wechat-series/24-logging-config-governance.md"};function l(t,s,o,g,d,h){return e(),a("div",null,[...s[0]||(s[0]=[n(`<h1 id="go-spring-实战第-24-课-——-日志配置-组织日志链路" tabindex="-1">Go-Spring 实战第 24 课 —— 日志配置：组织日志链路 <a class="header-anchor" href="#go-spring-实战第-24-课-——-日志配置-组织日志链路" aria-label="Permalink to &quot;Go-Spring 实战第 24 课 —— 日志配置：组织日志链路&quot;">​</a></h1><p>前面几篇文章，我们已经分别介绍了 Tag、Logger、Appender、Layout 和上下文提取。到了实际项目里，这些组件最终要通过配置组织起来：哪类日志交给哪个 Logger，采用同步还是异步方式，写到哪里，又使用什么格式。</p><p>这一篇不再分别介绍组件，而是从一份完整配置出发，看看 Go-Spring 怎样把它们连接成可以运行的日志链路。</p><h2 id="完整配置" tabindex="-1">完整配置 <a class="header-anchor" href="#完整配置" aria-label="Permalink to &quot;完整配置&quot;">​</a></h2><p>假设应用有两类日志：</p><ul><li>普通应用日志使用 INFO 级别，以文本格式输出到控制台。</li><li>业务日志匹配 <code>_biz_*</code> Tag，经过异步缓冲后，以 JSON 格式写入滚动文件。</li></ul><p>对应配置如下：</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 默认日志：同步输出到控制台</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">logging.logger.root.type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = ConsoleLogger</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">logging.logger.root.level</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = INFO</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">logging.logger.root.layout.type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = TextLayout</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 业务日志的输出目标：滚动文件</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">logging.appender.bizFile.type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = RollingFileAppender</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">logging.appender.bizFile.dir</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = ./logs</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">logging.appender.bizFile.file</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = biz.log</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">logging.appender.bizFile.interval</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = 1h</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">logging.appender.bizFile.maxAge</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = 168h</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">logging.appender.bizFile.layout.type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = JSONLayout</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">logging.appender.bizFile.layout.fileLineMaxLength</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = 48</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 业务日志的处理方式：异步写入 bizFile</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">logging.logger.biz.type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = AsyncLogger</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">logging.logger.biz.tag</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = _biz_*</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">logging.logger.biz.level</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = INFO</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">logging.logger.biz.bufferSize</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = 10000</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">logging.logger.biz.onBufferFull</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = discard</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">logging.logger.biz.appenderRef[0].</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ref</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = bizFile</span></span></code></pre></div><p>这份配置最终形成两条链路：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>其他 Tag  → root Logger → ConsoleAppender → TextLayout</span></span>
<span class="line"><span></span></span>
<span class="line"><span>_biz_*   → biz Logger  → bizFile Appender → JSONLayout</span></span>
<span class="line"><span>              │</span></span>
<span class="line"><span>              └─ AsyncLogger 后台异步调度</span></span></code></pre></div><p><code>root</code> 使用的是集成式 <code>ConsoleLogger</code>，内部已经包含控制台 Appender，因此配置比较紧凑。<code>biz</code> 使用组合式 <code>AsyncLogger</code>，输出目标单独定义为 <code>bizFile</code>，两者通过 <code>appenderRef</code> 连接。</p><h2 id="配置结构" tabindex="-1">配置结构 <a class="header-anchor" href="#配置结构" aria-label="Permalink to &quot;配置结构&quot;">​</a></h2><p>Go-Spring App 的日志配置统一位于 <code>logging</code> 前缀下。应用启动时，框架会取出这个前缀下的配置，再交给日志库。因此，日志库实际看到的是 <code>logger.*</code> 和 <code>appender.*</code>。</p><p>如果单独使用 <code>github.com/go-spring/log</code>，配置可以直接从这两个前缀开始，不需要增加 <code>logging</code>。</p><h3 id="实例与类型" tabindex="-1">实例与类型 <a class="header-anchor" href="#实例与类型" aria-label="Permalink to &quot;实例与类型&quot;">​</a></h3><p>下面两段配置分别定义了一个名为 <code>biz</code> 的 Logger 和一个名为 <code>bizFile</code> 的 Appender：</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">logging.logger.biz.type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = AsyncLogger</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">logging.appender.bizFile.type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = RollingFileAppender</span></span></code></pre></div><p>它们都遵循同一个结构：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>logging.&lt;组件类别&gt;.&lt;实例名&gt;.&lt;属性&gt;</span></span></code></pre></div><p><code>logger</code> 和 <code>appender</code> 表示组件类别，<code>biz</code> 和 <code>bizFile</code> 是配置中的实例名，<code>type</code> 决定使用哪个具体实现。后面的其他属性，则由这个实现负责解释。</p><p>例如，<code>AsyncLogger</code> 会读取 <code>bufferSize</code> 和 <code>onBufferFull</code>，<code>RollingFileAppender</code> 会读取 <code>dir</code>、<code>file</code>、<code>interval</code> 和 <code>maxAge</code>。Layout 是 Appender 或集成式 Logger 的子组件，因此继续放在对应实例的 <code>layout.*</code> 下面。</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">logging.appender.bizFile.layout.type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = JSONLayout</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">logging.appender.bizFile.layout.fileLineMaxLength</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = 48</span></span></code></pre></div><p>这样，一段配置既描述了要创建什么组件，也描述了组件之间的包含关系。</p><h3 id="tag-与级别" tabindex="-1">Tag 与级别 <a class="header-anchor" href="#tag-与级别" aria-label="Permalink to &quot;Tag 与级别&quot;">​</a></h3><p><code>biz</code> Logger 通过 <code>tag</code> 选择自己负责的日志：</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">logging.logger.biz.tag</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = _biz_*</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">logging.logger.biz.level</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = INFO</span></span></code></pre></div><p><code>_biz_order_create</code>、<code>_biz_user_login</code> 等 Tag 都会匹配 <code>_biz_*</code>。匹配到 <code>biz</code> 以后，Logger 再使用 <code>level</code> 判断日志是否继续处理。</p><p><code>root</code> 是特殊的兜底 Logger，不需要配置 <code>tag</code>。没有匹配到其他 Logger 的 Tag，最终都会进入 <code>root</code>。</p><p><code>level</code> 可以使用单个级别，也可以使用左闭右开的范围：</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># INFO 及以上</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">logging.logger.root.level</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = INFO</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># DEBUG 和 INFO，不包含 WARN</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">logging.logger.debug.level</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = DEBUG~WARN</span></span></code></pre></div><p>单个 <code>INFO</code> 等价于 <code>[INFO, MAX)</code>。级别范围和 Tag 路由的详细规则已经在第 21 课介绍过，这里只需要记住：<code>tag</code> 决定哪类日志进入 Logger，<code>level</code> 决定其中哪些级别继续处理。</p><h3 id="appenderref" tabindex="-1">AppenderRef <a class="header-anchor" href="#appenderref" aria-label="Permalink to &quot;AppenderRef&quot;">​</a></h3><p>组合式 Logger 只负责过滤和调度，不直接决定日志写到哪里。下面这行配置把 <code>biz</code> Logger 连接到前面定义的 <code>bizFile</code> Appender：</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">logging.logger.biz.appenderRef[0].</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ref</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = bizFile</span></span></code></pre></div><p><code>ref</code> 的值必须与 <code>logging.appender.&lt;实例名&gt;</code> 中的实例名一致。如果引用的 Appender 不存在，日志配置会在初始化阶段失败。</p><p>一个 Logger 可以连接多个输出目标。假设配置中还定义了一个名为 <code>console</code> 的 Appender：</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">logging.logger.biz.appenderRef[0].</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ref</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = console</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">logging.logger.biz.appenderRef[1].</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ref</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = bizFile</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">logging.logger.biz.appenderRef[1].</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">level</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = WARN~MAX</span></span></code></pre></div><p>这表示业务日志都会输出到 <code>console</code>，其中 WARN 及以上级别还会写入 <code>bizFile</code>。Logger 的 <code>level</code> 过滤整条链路，AppenderRef 的 <code>level</code> 只过滤当前输出分支。</p><p><code>appenderRef</code> 是对象数组，因此使用连续下标描述。简单字符串数组则既可以使用下标，也可以使用逗号分隔：</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">logging.logger.biz.tag</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = _biz_order_*,_biz_user_*</span></span></code></pre></div><p>等价于：</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">logging.logger.biz.tag[0] = _biz_order_*</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">logging.logger.biz.tag[1] = _biz_user_*</span></span></code></pre></div><p>到这里，完整配置的关系就清楚了：Logger 通过 <code>tag</code> 接住日志，通过 <code>level</code> 过滤日志，再通过 <code>appenderRef</code> 找到输出目标；Appender 最后使用自己的 Layout 生成输出内容。</p><h2 id="属性引用" tabindex="-1">属性引用 <a class="header-anchor" href="#属性引用" aria-label="Permalink to &quot;属性引用&quot;">​</a></h2><p>目录、级别和保留时间通常会随环境变化，可以使用 <code>\${key}</code> 把这些值集中定义：</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">logging.values.dir</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = /var/log/myapp</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">logging.values.level</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = INFO</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">logging.values.maxAge</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = 168h</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">logging.appender.bizFile.dir</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = \${values.dir}</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">logging.appender.bizFile.maxAge</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = \${values.maxAge}</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">logging.logger.biz.level</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = \${values.level}</span></span></code></pre></div><p>Go-Spring App 交给日志库的是 <code>logging</code> 下面的独立配置，所以被引用的 <code>values.*</code> 也要放在 <code>logging</code> 前缀下。不同 Profile、配置文件或命令行参数只需要覆盖这些值，不必重复整套日志结构。</p><p>普通属性会在注入组件前解析引用，但 <code>type</code> 不能使用属性引用。日志系统必须先读取 <code>type</code>，才能确定要创建哪种组件：</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 不支持</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">logging.logger.biz.type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = \${values.loggerType}</span></span></code></pre></div><h2 id="配置刷新" tabindex="-1">配置刷新 <a class="header-anchor" href="#配置刷新" aria-label="Permalink to &quot;配置刷新&quot;">​</a></h2><p>日志刷新不是修改当前组件的几个字段，而是根据新配置重建整条日志链路。单独使用日志库时，可以调用：</p><div class="language-go vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">err </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> log.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">RefreshConfig</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(config)</span></span></code></pre></div><p>刷新过程可以概括为：</p><ol><li>根据新配置创建 Logger、Appender 和 Layout。</li><li>解析 <code>appenderRef</code>，检查引用和并发组合是否合法。</li><li>先启动新 Appender，再启动新 Logger。</li><li>将已有 Tag 和命名 Logger 绑定到新 Logger。</li><li>停止旧 Logger 和旧 Appender。</li></ol><p>如果创建、引用解析或启动失败，本次刷新会返回 error，已经启动的临时组件会被停止，当前正在使用的日志链路不会被替换。</p><p>Go-Spring App 会在启动阶段根据 <code>logging.*</code> 初始化日志。运行期调用 <code>PropertiesRefresher.RefreshProperties()</code> 只会刷新动态配置字段，不会自动重建日志链路。应用确实需要动态调整日志配置时，应当显式调用日志库的 <code>Refresh</code> 或 <code>RefreshConfig</code>。</p><p>刷新会逐个替换 Tag 和命名 Logger 内部的 Logger 引用，并不会让所有调用点在同一个瞬间完成事务式切换。因此，它适合低频配置调整，不应当被当作逐条日志无损切换机制。</p><p>日志配置的核心不是罗列每个组件的所有属性，而是描述一条完整关系：Tag 选择 Logger，Logger 通过 AppenderRef 连接输出目标，Appender 再使用 Layout 生成最终内容。掌握这条主线以后，新增 Logger、增加输出分支或者切换格式，都只是沿着同一套配置结构进行调整。</p>`,58)])])}const k=i(p,[["render",l]]);export{c as __pageData,k as default};
